// Minimal "retriever": pick the HR policy doc whose keywords best match the query.
const body = $json.body || {};
const query = (body.query || body.prompt || '').toString();

// Richer corpus: each doc carries the core fact PLUS buried exceptions and
// conditions, and several docs deliberately collide (two "bonus" docs, several
// "notice"/"probation"/"leave" docs, the number 5 vs 10, 119 in two places).
// The retriever returns only the SINGLE best doc, so multi-topic or ambiguous
// questions get partial context — fertile ground for confidently-wrong answers.
const CORPUS = {
  annual_leave:   "Annual Leave: Full-time employees accrue 18 days of paid annual leave per calendar year. Up to 5 unused days carry over to the next year; the rest is forfeited on December 31. Managers (grade M3 and above) may instead carry over up to 10 days. Leave may not be taken during the first 90 days of probation. Part-time staff accrue on a pro-rata basis.",
  sick_leave:     "Sick Leave: Employees receive 30 days of paid sick leave per calendar year. Absences of 1 to 2 days may be self-certified; a medical certificate is required for any absence of 3 or more consecutive days. Sick leave does not carry over and is not paid out on resignation. Employees in their first 3 months receive a reduced entitlement of 10 days.",
  parental_leave: "Parental Leave: Primary caregivers receive 16 weeks of paid parental leave; secondary caregivers receive 4 weeks. Employees must have 12 months of continuous service to qualify. Leave must begin within 12 months of the birth or legal adoption. Notice of at least 8 weeks is required where practicable.",
  remote_work:    "Remote Work: Employees may work remotely up to 3 days per week with manager approval. New employees may not work remotely during their first 3 months. Fully remote arrangements require Director sign-off and come with a 5000 THB per year home-office stipend. Core collaboration hours are 10:00 to 15:00 local time.",
  expenses:       "Expense Reimbursement: Business expenses are reimbursed when submitted within 60 days with an itemized receipt. Meals while travelling are capped at 800 THB per day. Alcohol is not reimbursable. Client entertainment above 2000 THB requires prior VP approval. Personal expenses are never reimbursable.",
  overtime:       "Overtime: Overtime is paid at 1.5x the hourly rate on workdays and 2x on public holidays. Overtime must be approved in advance. Employees above manager grade are not eligible for overtime pay. With approval, time off in lieu may be taken instead of pay.",
  referral:       "Referral Bonus: Employees who refer an external candidate that is hired receive a 20000 THB referral bonus, paid in the payroll cycle after the new hire passes their 119-day probation. Referrals of contractors or interns do not qualify. There is no limit on the number of referrals.",
  health:         "Health Insurance: All full-time employees are enrolled in group health insurance from day one. Coverage includes outpatient, inpatient, and dental up to 20000 THB per year. Optical is not covered. Dependents may be added at the employee's own cost. Pre-existing conditions are covered after a 90-day waiting period.",
  resignation:    "Resignation and Notice: Permanent employees must give 30 days written notice. Employees still in their first year give 15 days notice. Unused annual leave is paid out on resignation; unused sick leave is not paid out.",
  probation:      "Probation: New employees serve a probation period of 119 days. During probation either party may end employment with 7 days notice. No annual leave may be taken during probation. Performance is reviewed at day 60 and day 110.",
  performance_bonus: "Performance Bonus: An annual performance bonus of up to one month's salary is paid in December to employees rated 4 or above in the annual review. Employees on a performance improvement plan are not eligible. This is separate from the referral bonus.",
  conduct:        "Code of Conduct: Employees may not accept gifts worth more than 1000 THB from vendors or clients. Conflicts of interest must be declared to HR in writing. Harassment and discrimination are prohibited and may lead to termination."
};

// Keyword lists are intentionally overlapping so the single-best retriever can
// pick the WRONG doc on ambiguous questions (e.g. "bonus", "notice", "leave").
const KEYWORDS = {
  annual_leave:   ["annual leave","vacation","holiday entitlement","carry over","carryover","18 days","leave"],
  sick_leave:     ["sick","medical certificate","illness","30 days","self-certify","self certify"],
  parental_leave: ["parental","maternity","paternity","caregiver","baby","adoption","16 weeks","newborn","leave"],
  remote_work:    ["remote","work from home","wfh","home office","stipend","core hours"],
  expenses:       ["expense","reimburse","meal","alcohol","receipt","per diem","entertainment"],
  overtime:       ["overtime","1.5x","2x","time off in lieu","public holiday rate"],
  referral:       ["referral","refer","referred","referral bonus","bonus"],
  health:         ["health","insurance","dental","medical plan","dependent","optical","coverage"],
  resignation:    ["resign","resignation","notice period","quit","leaving the company","last day","leave"],
  probation:      ["probation","probationary","trial period"],
  performance_bonus: ["performance bonus","annual bonus","year-end bonus","year end bonus","december bonus","bonus"],
  conduct:        ["gift","gifts","conduct","conflict of interest","vendor"]
};

const q = query.toLowerCase();
let best = null, bestScore = 0;
for (const [doc, words] of Object.entries(KEYWORDS)) {
  let s = 0;
  for (const w of words) { if (q.includes(w)) s += 1; }
  if (s > bestScore) { bestScore = s; best = doc; }   // strict > : on a TIE the first-defined doc wins
}

// If nothing matched, return an empty-ish context so the bot must refuse.
const context = best ? CORPUS[best] : "No relevant HR policy was found for this question.";

// Build the FULL OpenAI request body here (real values, no nested n8n expressions).
// This is the bot's "prompt" — students edit the system message in Step 4.
const system = [
  "You are Acme Corp's HR assistant.",
  "Answer the employee's question using ONLY the policy context provided.",
  "If the context does not contain the answer, say you could not find it in policy and do not guess.",
  "Be concise."
].join(" ");

const openaiBody = {
  model: "gpt-4o-mini",
  temperature: 0,
  messages: [
    { role: "system", content: system + "\n\nCONTEXT:\n" + context },
    { role: "user", content: query }
  ]
};

return [{ json: { query, context, openaiBody } }];

// Read the OpenAI chat response and the context we retrieved, return a clean contract.
const llm = $json;  // output of the HTTP Request (OpenAI) node
const answer = (llm.choices && llm.choices[0] && llm.choices[0].message && llm.choices[0].message.content) || "";
const model = llm.model || "unknown";

// Pull the context forward from the retrieve node.
const ctx = $('Retrieve HR context').first().json.context;
const query = $('Retrieve HR context').first().json.query;

return [{ json: { answer: answer.trim(), context: ctx, model, query } }];
